import React, { useState, useEffect } from 'react'
import { Table } from 'antd';
import Api from '../../helpers/api';
import handleApiError from '../../helpers/handleApiError';
import timeStampsFormat from '../../helpers/dateFormat';

const api = new Api();

const FormMaterialDetail = (props) => {

    const [loading, setLoading] = useState(false)
    const [stock, setStock] = useState(false)

    useEffect(() => {
        viewStock()
    }, []);

    const viewStock = () => {
        setLoading(true)
        const { id } = props.match.params
        api.viewStock(id)
            .then(response => {
                setLoading(false)
                setStock(response.data)
            }).catch(error => {
                handleApiError(error, props)
            })
    }

    const columns = [
        {
            title: 'Field',
            dataIndex: 'field',
            width: 50
        },
        {
            title: 'Value',
            dataIndex: 'value',
            width: 150
        },
    ];

    const data = [
        {
            field: 'Plant',
            value: stock.room && stock.room.plant ? stock.room.plant.name : '-'
        },
        {
            field: 'Room',
            value: stock.room ? stock.room.name : '-'
        },
        {
            field: 'Material',
            value: stock.material ? `${stock.material.material_code} - ${stock.material.description}` : '-'
        },
        {
            field: 'Classification',
            value: stock.material ? stock.material.classification.name : '-'
        },
        {
            field: 'Require Serial Number?',
            value: stock.material ? stock.material.serial_number ? 'Yes' : 'No' : '-'
        },
        {
            field: 'UoM',
            value: stock.material && stock.material.uom ? stock.material.uom.name : '-'
        },
        {
            field: 'Ready Stock',
            value: stock.stock
        },
        {
            field: 'Quantity In Transait',
            value: stock.quantity_in_transit
        },
        {
            field: 'Minimum Stock',
            value: stock.minimum_stock
        },
        {
            field: 'Updated by',
            value: stock.updated_by ? `${stock.updated_by.fullname} - ${stock.updated_by.email}` : '-'
        },
        {
            field: 'Updated at',
            value: timeStampsFormat(stock.updated_at)
        },
    ];

    return (
        <Table
            loading={loading}
            columns={columns}
            dataSource={data}
            size="small"
            pagination={false}
        />
    )
}

export default FormMaterialDetail;