import React, { useState, useEffect } from 'react'
import { Table, Space, Button, Row, Col, Input, Tabs } from 'antd';
import Api from '../../helpers/api';

import {
    QrcodeOutlined
} from '@ant-design/icons';
import handleApiError from '../../helpers/handleApiError';

const { TabPane } = Tabs;

const api = new Api();

const TableSerialNumber = (props) => {

    const [selectedRowKeys, setSelectedRowKeys] = useState([])
    const [loading, setLoading] = useState(false)
    const [data, setData] = useState([])
    const [pagination, setPagination] = useState({})
    const [q, setQ] = useState('')

    useEffect(() => {
        fetch()
    }, [q])

    const fetch = (params = {}) => {
        setLoading(true)
        const { id } = props.match.params

        api.getStockHistoryByStockId(id, { ...params, q })
            .then(response => {
                const data = response.data;

                let pagination = {}

                pagination.current = data.current_page
                pagination.total = data.total;
                pagination.pageSize = parseInt(data.per_page);

                setData(data.data)
                setPagination(pagination)
                setLoading(false)
            })
            .catch(error => {
                setLoading(false)
                handleApiError(error, props)
            })
    }

    const handlePrintQr = (size) => {
        let id = []
        selectedRowKeys.map(item => id.push(`id[]=${item}`))
        id.push(`size=${size}`)

        let apiUrl = process.env.REACT_APP_API_URL;
        let fullUrl = `${apiUrl}/transaction/stock-detail/qrcode?${id.join('&')}`
        window.open(fullUrl)
    }

    const searchData = (q) => {
        setQ(q);
    }

    const handleTableChange = (paginate, sorter) => {
        const pager = { ...pagination };
        pager.current = paginate.current;

        setPagination(pager)

        fetch({
            per_page: paginate.pageSize,
            page: paginate.current,
            sort_field: sorter.field,
            sort_order: sorter.order === 'ascend' ? 'asc' : 'desc',
        });
    }

    //on check table item
    const onSelectChange = (selectedRowKeys) => {
        setSelectedRowKeys(selectedRowKeys)
    }

    const rowSelection = {
        selectedRowKeys,
        onChange: onSelectChange,
    };

    const hasSelected = selectedRowKeys.length > 0;

    const columns = [
        {
            title: 'Code',
            dataIndex: 'code',
            width: 100
        },
        {
            title: 'Serial Number',
            dataIndex: 'serial_number',
            width: 150
        },
        {
            title: 'Material',
            dataIndex: 'stock',
            width: 150,
            render: (stock) => (
                stock && stock ? `${stock.material.material_code} - ${stock.material.description}` : '-'
            ),
        },
    ];

    return (
        <Tabs defaultActiveKey="1" >
            <TabPane tab="Ready Stock" key="1">
                <Space direction="vertical" size="large" style={{ width: '100%' }}>
                    <Row>
                        <Col md={19}>
                            <Space>
                                <Button
                                    onClick={() => handlePrintQr('m24')}
                                    disabled={!hasSelected}
                                    icon={<QrcodeOutlined />}
                                >Qr Code 70x24MM</Button>

                                <Button
                                    onClick={() => handlePrintQr('s24')}
                                    disabled={!hasSelected}
                                    icon={<QrcodeOutlined />}
                                >Qr Code 24x24MM</Button>
                            </Space>
                        </Col>

                        <Col md={5} >
                            <Input.Search placeholder="Search"
                                onSearch={searchData}
                            />
                        </Col>
                    </Row>
                    <Table
                        loading={loading}
                        rowSelection={rowSelection}
                        columns={columns}
                        rowKey={record => record.id}
                        onChange={handleTableChange}
                        dataSource={data}
                        pagination={{
                            pageSizeOptions: ['20', '50', '100', '200'],
                            showSizeChanger: true,
                            showQuickJumper: true,
                            showTotal: (total, range) => `${range[0]}-${range[1]} of ${total} items`,
                            ...pagination
                        }}
                        // size='small'
                        scroll={{ y: 300, x: 1000 }} />
                </Space>
            </TabPane>
        </Tabs>
    )
}

export default TableSerialNumber;